public static String unescapeJava(String str) throws Exception {
    if (str == null) {
        return null;
    }
    // Mapa de caracteres escapados comunes en Java
    Map<String, String> unescapeMap = new HashMap<>();
    // nueva línea
    unescapeMap.put("\\n", "\n");
